using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class ReportsTraining : TrainingContentBase
{
    public ReportsTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Reports Overview",
            Slug = "reports-overview",
            Summary = "What the report builder does, entity sources, pre-built templates, chart visualizations, and export options.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/reports"]""",
            Tags = """["reports","analytics","charts","export"]""",
            ContentJson = """{"body":"## Reports Overview\n\nThe Reports module is the central analytics hub for QB Engineer. It provides two complementary systems: a library of 27 pre-built report templates covering common operational questions, and a dynamic Report Builder that lets you query any of 28 entity sources with 350+ fields to construct custom reports from scratch.\n\n### Three Report Sections\n\nThe Reports page is organized into three sections, accessible via the top navigation:\n\n1. **Pre-Built Reports** — The default landing page. A left sidebar lists 27 ready-made reports organized by domain (production, financial, personal, quality, etc.). Click any report to load its chart and data table. Reports that depend on a date range (like Time by User or Revenue) show date pickers in the header.\n\n2. **Report Builder** — A dynamic query tool. Select an entity source (e.g., Jobs, Parts, Invoices), pick columns, add filters, choose grouping and sorting, then run the query. Results display in a data table with optional chart visualization. Save your configurations as named reports to reuse later.\n\n3. **Sankey Flow Reports** — Visual flow diagrams showing how data moves through your business: Quote-to-Cash, Job Stage Flow, Material-to-Product, Worker Orders, Expense Flow, Vendor Supply Chain, Quality Rejection, Inventory Location, Customer Revenue, and Training Completion.\n\n### Pre-Built Report Templates (27)\n\nThe pre-built reports cover every major domain:\n\n**Production & Operations:**\n- **Jobs by Stage** — Bar chart showing job counts per kanban stage\n- **Overdue Jobs** — Table of jobs past their due date\n- **Job Completion Trend** — Line chart of jobs completed over time\n- **On-Time Delivery** — Percentage of jobs delivered on or before due date\n- **Average Lead Time** — Average days from job creation to completion by track type\n- **Time in Stage** — How long jobs spend in each stage\n- **Job Margin** — Revenue vs. cost analysis per job\n- **Cycle Review** — Planning cycle performance summary\n- **R&D Report** — R&D/tooling track activity and outcomes\n\n**People & Time:**\n- **Time by User** — Hours logged per team member (date range required)\n- **Team Workload** — Current job assignments per user\n- **Employee Productivity** — Output metrics per employee\n- **My Work History** — Personal job completion history\n- **My Time Log** — Personal time entries\n- **My Cycle Summary** — Personal planning cycle performance\n- **My Expense History** — Personal expense submissions\n\n**Sales & Financial:**\n- **Expense Summary** — Spending by category\n- **Lead Pipeline** — Lead counts by status\n- **Customer Activity** — Customer engagement metrics\n- **AR Aging** — Outstanding receivables by aging bucket\n- **Revenue** — Revenue over time\n- **Profit & Loss** — Simple income vs. expenses\n- **Quote-to-Close** — Quote conversion rates and timelines\n- **Lead-to-Sales** — Lead conversion funnel\n\n**Logistics & Quality:**\n- **Shipping Summary** — Shipment volume and carrier usage\n- **Inventory Levels** — Current stock quantities\n- **Maintenance** — Asset maintenance activity and costs\n- **Quality/Scrap** — Scrap rates and quality inspection results\n\n### The Dynamic Report Builder\n\nThe Report Builder gives you full control over what data you query and how it is presented.\n\n**Step 1 — Choose a Data Source:** Select from 28 entity sources. Each source exposes a different set of fields. Sources include: Jobs, Parts, Customers, Expenses, Time Entries, Invoices, Leads, Assets, Purchase Orders, Sales Orders, Quotes, Shipments, Inventory (Bin Contents), Payments, Vendors, Production Runs, Lot Records, QC Inspections, Maintenance Schedules, Maintenance Logs, Downtime Logs, Customer Returns, Bin Movements, Planning Cycles, Invoice Lines, Sales Order Lines, Purchase Order Lines, and Quote Lines.\n\n**Step 2 — Select Columns:** Check the fields you want included in your results. Each entity source has 10–35 fields available including related entity fields (e.g., Customer Name on a Job, Vendor Name on a PO).\n\n**Step 3 — Add Filters:** Build filter conditions using field + operator + value. Operators include Equals, NotEquals, Contains, StartsWith, GreaterThan, LessThan, GreaterThanOrEqual, LessThanOrEqual, Between, IsNull, IsNotNull, and In.\n\n**Step 4 — Group & Sort:** Optionally group results by any groupable field (typically enums, dates, and category fields). Sort by any sortable field, ascending or descending.\n\n**Step 5 — Visualize:** Choose a chart type: Bar, Line, Pie, Doughnut, or Table (data only). For chart visualizations, select a label field (the axis/segment labels) and a value field (must be numeric — the measurement).\n\n**Run and Save:** Click Run Report to execute the query. Results appear in a data table below the configuration panel. Save your configuration as a named report with an optional description and a shared/private toggle. Saved reports appear in the toolbar dropdown for quick access.\n\n### Chart Visualizations\n\nBoth pre-built reports and the Report Builder use ng2-charts (Chart.js) for visualization:\n\n- **Bar charts** — Used for categorical comparisons (jobs by stage, time by user, expenses by category)\n- **Line charts** — Used for trends over time (completion trend, revenue, lead time)\n- **Pie charts** — Used for proportional breakdowns (lead pipeline, expense distribution)\n- **Doughnut charts** — Similar to pie, used for status distributions\n- **Sankey diagrams** — Flow visualizations showing data movement between stages\n\nCharts support drill-down: click a bar or slice to filter the data table to that segment. Click again or use the breadcrumb to return to the full view.\n\n### Export Options\n\n- **CSV Export** — Click the CSV button after running a report to download results as a comma-separated file. Available in the Report Builder.\n- **PDF Export** — Server-side PDF generation via QuestPDF for formatted report output.\n- **Print** — Browser print styling hides navigation and interactive controls, showing only the report content.\n\n### Roles and Access\n\nThe Reports module is available to Admin, Manager, Office Manager, and PM roles. Engineers and Production Workers do not have direct access to the full reports page, though personal reports (My Work History, My Time Log, My Expense History) are available through their respective feature pages.\n\n### Saved Reports\n\nSaved reports store the complete configuration: entity source, selected columns, filters, grouping, sorting, chart type, and chart field mappings. Reports can be marked as shared (visible to all users with report access) or private (visible only to the creator). Saved reports are loaded from the toolbar dropdown and can be updated or deleted.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Reports — Guided Tour",
            Slug = "reports-walkthrough",
            Summary = "A guided tour of the reports page: pre-built reports, date range filters, charts, the report builder, and sankey diagrams.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/reports"]""",
            Tags = """["reports","analytics","walkthrough"]""",
            ContentJson = """{"appRoute":"/reports","startButtonLabel":"Tour Reports","steps":[{"element":".reports-sidebar","popover":{"title":"Report Navigation Sidebar","description":"The left sidebar lists all 27 pre-built reports. Click any report name to load it. Reports are organized by domain: production, time tracking, financial, quality, and personal. The active report is highlighted.","side":"right"}},{"element":".report-header","popover":{"title":"Report Header & Filters","description":"Shows the active report title. Some reports include date range filters (From / To date pickers) — these appear when the selected report requires a date range (e.g., Time by User, Revenue, Expense Summary). Set the dates and click Apply to refresh the data.","side":"bottom"}},{"element":"canvas","popover":{"title":"Chart Visualization","description":"Each pre-built report renders a chart: bar charts for comparisons, line charts for trends, pie/doughnut for proportions. Click on a bar or slice to drill down into that segment — the data table below filters to show only the matching rows.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Report Data Table","description":"Below the chart, a data table shows the raw data. Columns are sortable — click headers to sort. The table supports all standard DataTable features: column filtering, column visibility, and pagination.","side":"top"}},{"element":".report-nav-item:last-of-type","popover":{"title":"Report Builder","description":"The Report Builder lets you create custom reports by choosing an entity source, selecting columns, adding filters, and configuring charts. You can save your configurations for reuse. Sankey flow diagrams are also available for visual flow analysis.","side":"right"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Reports Field Reference",
            Slug = "reports-field-reference",
            Summary = "Complete reference for the report builder: entity sources, field types, filter operators, chart types, export formats, saved report fields, and actions.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/reports"]""",
            Tags = """["reports","analytics","reference"]""",
            ContentJson = """{"title":"Reports Field Reference","groups":[{"heading":"Entity Sources (28)","items":[{"label":"Jobs","value":"Production jobs with stage, priority, customer, part, track type, dates, disposition. 33 fields."},{"label":"Parts","value":"Parts catalog with part number, type, status, material, vendor, tooling. 19 fields."},{"label":"Customers","value":"Customer records with name, company, email, phone, active status. 10 fields."},{"label":"Expenses","value":"Expense records with amount, category, status, date, job linkage, approval. 17 fields."},{"label":"Time Entries","value":"Time tracking with duration, category, job, timer start/stop, manual flag. 14 fields."},{"label":"Invoices","value":"Invoice records with number, status, dates, credit terms, tax rate, customer, sales order. 19 fields."},{"label":"Leads","value":"Lead pipeline with company, contact, source, status, follow-up date, lost reason. 15 fields."},{"label":"Assets","value":"Equipment and tooling with type, status, hours, manufacturer, tooling fields (cavity count, shot count). 22 fields."},{"label":"Purchase Orders","value":"PO records with number, status, dates, vendor, job linkage. 18 fields."},{"label":"Sales Orders","value":"Sales order records with number, status, customer PO, credit terms, customer, quote. 17 fields."},{"label":"Quotes","value":"Quote records with number, status, dates, tax rate, customer. 15 fields."},{"label":"Shipments","value":"Shipment records with number, status, carrier, tracking, dates, cost, weight, sales order. 17 fields."},{"label":"Inventory (Bin Contents)","value":"Bin content records with entity type, quantity, reserved qty, lot number, status, location, job. 16 fields."},{"label":"Payments","value":"Payment records with number, method, amount, date, reference number, customer. 15 fields."},{"label":"Vendors","value":"Vendor records with company, contact, address, payment terms, active status. 17 fields."},{"label":"Production Runs","value":"Production run records with run number, status, quantities (target, completed, scrap), times, job, part. 20 fields."},{"label":"Lot Records","value":"Lot traceability with lot number, quantity, expiration, supplier lot, part, job, production run. 17 fields."},{"label":"QC Inspections","value":"Quality inspection records with status, lot number, job, production run, template, inspector. 16 fields."},{"label":"Maintenance Schedules","value":"Scheduled maintenance with title, intervals, last performed, next due, asset. 16 fields."},{"label":"Maintenance Logs","value":"Maintenance history with performed date, hours, cost, schedule, asset. 10 fields."},{"label":"Downtime Logs","value":"Asset downtime with start/end, reason, resolution, planned flag, asset. 13 fields."},{"label":"Customer Returns","value":"Return records with number, status, reason, dates, inspection, original/rework job. 17 fields."},{"label":"Bin Movements","value":"Inventory movements with entity, quantity, lot, reason, from/to location. 12 fields."},{"label":"Planning Cycles","value":"Planning cycle records with name, status, dates, duration, goals. 9 fields."},{"label":"Invoice Lines","value":"Invoice line items with line number, description, quantity, unit price, invoice, part. 13 fields."},{"label":"Sales Order Lines","value":"SO line items with line number, description, quantity, unit price, shipped qty, sales order, part. 14 fields."},{"label":"Purchase Order Lines","value":"PO line items with description, ordered/received qty, unit price, PO, part. 14 fields."},{"label":"Quote Lines","value":"Quote line items with line number, description, quantity, unit price, quote, part. 14 fields."}]},{"heading":"Field Types","items":[{"label":"string","value":"Text fields. Supports Contains, StartsWith, Equals, NotEquals, IsNull, IsNotNull operators."},{"label":"number","value":"Numeric fields. Supports Equals, NotEquals, GreaterThan, LessThan, GreaterThanOrEqual, LessThanOrEqual, Between, IsNull, IsNotNull operators. Used as chart value fields."},{"label":"date","value":"Date/time fields. Supports Equals, GreaterThan, LessThan, Between, IsNull, IsNotNull operators. Groupable by date for time-series charts."},{"label":"boolean","value":"True/false fields (e.g., Archived, Active, Manual Entry). Supports Equals operator. Groupable for segmentation."},{"label":"enum","value":"Enumerated values (e.g., Status, Priority, Type). Supports Equals, NotEquals, In operators. Groupable for categorical charts."}]},{"heading":"Filter Operators","items":[{"label":"Equals","value":"Exact match. Works with all field types."},{"label":"NotEquals","value":"Not an exact match. Works with all field types."},{"label":"Contains","value":"Substring match (case-insensitive). Works with string fields."},{"label":"StartsWith","value":"Prefix match. Works with string fields."},{"label":"GreaterThan","value":"Value is greater than the filter value. Works with number and date fields."},{"label":"LessThan","value":"Value is less than the filter value. Works with number and date fields."},{"label":"GreaterThanOrEqual","value":"Value is greater than or equal. Works with number and date fields."},{"label":"LessThanOrEqual","value":"Value is less than or equal. Works with number and date fields."},{"label":"Between","value":"Value falls between two values (inclusive). Requires value and value2. Works with number and date fields."},{"label":"IsNull","value":"Field has no value. No filter value needed."},{"label":"IsNotNull","value":"Field has a value. No filter value needed."},{"label":"In","value":"Value matches one of a comma-separated list. Works with enum fields."}]},{"heading":"Chart Types","items":[{"label":"Bar","value":"Vertical bar chart. Best for categorical comparisons (jobs by stage, expenses by category). Requires a label field and a numeric value field."},{"label":"Line","value":"Line chart with data points. Best for trends over time (completion trend, revenue). Requires a label field and a numeric value field."},{"label":"Pie","value":"Circular chart divided into proportional slices. Best for showing composition (lead pipeline, status distribution). Requires a label field and a numeric value field."},{"label":"Doughnut","value":"Like pie chart with a hollow center. Used for status or type distributions. Requires a label field and a numeric value field."},{"label":"Table","value":"Data table only, no chart visualization. Default when no chart type is selected. Shows results in the sortable, filterable DataTable."}]},{"heading":"Export Formats","items":[{"label":"CSV","value":"Comma-separated values file. Downloads all result rows with selected columns. Available after running a report in the Report Builder. Button appears in the actions bar."},{"label":"PDF","value":"Server-generated PDF via QuestPDF. Formatted report with headers, data table, and metadata. Generated via the API export endpoint."},{"label":"Print","value":"Browser print. The @media print stylesheet hides navigation, sidebar, and interactive controls, showing only the report content and chart."}]},{"heading":"Saved Report Fields","items":[{"label":"Name (required)","value":"Text input, max 100 characters. Identifies the saved report in the toolbar dropdown."},{"label":"Description","value":"Textarea, optional. Additional context about what the report shows."},{"label":"Shared toggle","value":"When ON, the report is visible to all users with report access. When OFF, only the creator can see it."},{"label":"Entity Source","value":"The data source selected when building the report (e.g., Jobs, Parts). Saved automatically."},{"label":"Columns","value":"The checked fields. Saved automatically with the report configuration."},{"label":"Filters","value":"All filter rows (field + operator + value). Saved automatically."},{"label":"Group By","value":"The grouping field, if any. Saved automatically."},{"label":"Sort Field + Direction","value":"The sort column and asc/desc direction. Saved automatically."},{"label":"Chart Type + Fields","value":"The chart type, label field, and value field. Saved automatically."}]},{"heading":"Buttons and Actions","items":[{"label":"Report sidebar items","value":"Click any pre-built report name to load it. Active report is highlighted. 27 reports available."},{"label":"Report Builder link","value":"Navigates to /reports/builder. Opens the dynamic query builder page."},{"label":"Sankey Reports link","value":"Navigates to /reports/sankey. Opens the Sankey flow diagram page with 10 flow visualizations."},{"label":"Run Report (builder)","value":"Executes the configured query. Disabled until an entity source is selected and at least one column is checked."},{"label":"Save (builder)","value":"Opens the Save Report dialog. Disabled until the report can be run. Prompts for name, description, and shared toggle."},{"label":"CSV (builder)","value":"Exports current results to a CSV file. Only visible after running a report."},{"label":"New Report (builder)","value":"Clears the current configuration (entity, columns, filters, chart settings) and starts fresh."},{"label":"Load Saved Report (builder dropdown)","value":"Toolbar dropdown listing all saved reports. Selecting one loads its full configuration. Shows '-- None --' as the first option."},{"label":"Delete Saved Report (builder)","value":"Red trash icon next to the saved report dropdown. Visible only when a saved report is loaded. Deletes the saved report."},{"label":"Add Filter (builder)","value":"Adds a new filter row with field, operator, and value controls. Multiple filters can be stacked."},{"label":"Remove Filter (builder)","value":"Red X icon on each filter row. Removes that filter condition."},{"label":"Chart drill-down","value":"Click a bar segment or pie/doughnut slice to filter the data table to that segment. Click again to return to the full view."}]},{"heading":"Validation Rules","items":[{"label":"Entity Source","value":"Required to run or save a report. Must select one of the 28 available sources."},{"label":"Columns","value":"At least one column must be selected to run the report."},{"label":"Filter value","value":"Required for most operators. Not required for IsNull and IsNotNull."},{"label":"Chart label/value fields","value":"Required when a chart type other than Table is selected. Value field must be a numeric field."},{"label":"Save Report — Name","value":"Required, max 100 characters."}]},{"heading":"Sankey Flow Reports (10)","items":[{"label":"Quote-to-Cash","value":"Shows the flow from quotes through sales orders, shipments, invoices, to payments. Date range required."},{"label":"Job Stage Flow","value":"Visualizes how jobs move between kanban stages across track types."},{"label":"Material-to-Product","value":"Maps raw materials (BOM) through production to finished parts."},{"label":"Worker Orders","value":"Shows job assignments flowing from workers to completion status."},{"label":"Expense Flow","value":"Tracks expense categories through approval to final status. Date range required."},{"label":"Vendor Supply Chain","value":"Maps vendors through purchase orders to received materials."},{"label":"Quality Rejection","value":"Shows quality inspection results flowing through pass/fail/rework outcomes. Date range required."},{"label":"Inventory Location","value":"Visualizes inventory distribution across storage locations and bins."},{"label":"Customer Revenue","value":"Maps customers through orders and invoices to revenue. Date range required."},{"label":"Training Completion","value":"Shows training modules flowing through enrollment to completion status."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Reports Knowledge Check",
            Slug = "reports-quiz",
            Summary = "Test your knowledge of the Reports module: pre-built reports, the report builder, entity sources, filters, charts, and export.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/training"]""",
            Tags = """["reports","analytics","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"rpt1","text":"You want to see how many jobs are currently in each kanban stage. Which pre-built report should you use?","options":[{"id":"a","text":"Jobs by Stage","isCorrect":true},{"id":"b","text":"Job Completion Trend"},{"id":"c","text":"Time in Stage"},{"id":"d","text":"Team Workload"}],"explanation":"Jobs by Stage shows a bar chart of job counts per kanban stage. Job Completion Trend shows completions over time, Time in Stage shows duration spent in each stage, and Team Workload shows assignments per user."},{"id":"rpt2","text":"In the Report Builder, what is the minimum configuration needed to run a report?","options":[{"id":"a","text":"Select an entity source and choose at least one column","isCorrect":true},{"id":"b","text":"Select an entity source, add at least one filter, and choose a chart type"},{"id":"c","text":"Select an entity source only — columns are auto-selected"},{"id":"d","text":"Load a saved report — you cannot run an ad-hoc query"}],"explanation":"The Run Report button is enabled once you select an entity source and check at least one column. Filters, grouping, sorting, and chart type are all optional."},{"id":"rpt3","text":"You need to find all invoices sent to a specific customer in Q1. In the Report Builder, how do you set this up?","options":[{"id":"a","text":"Select Invoices as the entity source, add a filter on Customer Name (Equals), and add a filter on Invoice Date (Between) with Q1 start and end dates","isCorrect":true},{"id":"b","text":"Select Customers as the entity source and filter by invoice count"},{"id":"c","text":"Use the AR Aging pre-built report and filter by customer"},{"id":"d","text":"Select Invoice Lines and group by customer name"}],"explanation":"Use the Invoices entity source, then add two filters: one for Customer.Name (Equals) with the customer name, and one for InvoiceDate (Between) with the Q1 date range. The Between operator requires two values."},{"id":"rpt4","text":"What does the 'Shared' toggle do when saving a report in the Report Builder?","options":[{"id":"a","text":"When ON, the report is visible to all users with report access. When OFF, only the creator can see it.","isCorrect":true},{"id":"b","text":"When ON, the report results are cached and shared across sessions"},{"id":"c","text":"When ON, the report is exported to a shared network drive"},{"id":"d","text":"When ON, the report sends email notifications to all managers"}],"explanation":"The Shared toggle controls visibility. Shared reports appear in the Saved Reports dropdown for all users who have access to the Reports module (Admin, Manager, Office Manager, PM). Private reports are visible only to the creator."},{"id":"rpt5","text":"You want to create a pie chart showing expenses by category. In the Report Builder, which fields do you configure?","options":[{"id":"a","text":"Set chart type to Pie, label field to Category, and value field to Amount","isCorrect":true},{"id":"b","text":"Set chart type to Pie and select Category as the only column"},{"id":"c","text":"Set chart type to Pie, group by Category, and sort by Amount"},{"id":"d","text":"Set chart type to Bar and label field to Category — pie charts are not supported"}],"explanation":"For any chart visualization, you need three settings: Chart Type (Pie), Label Field (the category/segment axis — Category), and Value Field (must be numeric — Amount). The label field determines what each slice represents, and the value field determines its size."},{"id":"rpt6","text":"Which filter operator would you use to find all jobs where the Due Date has not been set?","options":[{"id":"a","text":"IsNull","isCorrect":true},{"id":"b","text":"Equals with an empty value"},{"id":"c","text":"NotEquals with today's date"},{"id":"d","text":"LessThan with a very old date"}],"explanation":"The IsNull operator checks whether a field has no value at all. It does not require a filter value. This is the correct way to find records with missing dates, as opposed to comparing against empty strings or arbitrary dates."},{"id":"rpt7","text":"How many entity sources are available in the Report Builder?","options":[{"id":"a","text":"10"},{"id":"b","text":"20"},{"id":"c","text":"28","isCorrect":true},{"id":"d","text":"35"}],"explanation":"The Report Builder provides 28 entity sources: Jobs, Parts, Customers, Expenses, Time Entries, Invoices, Leads, Assets, Purchase Orders, Sales Orders, Quotes, Shipments, Inventory, Payments, Vendors, Production Runs, Lot Records, QC Inspections, Maintenance Schedules, Maintenance Logs, Downtime Logs, Customer Returns, Bin Movements, Planning Cycles, Invoice Lines, Sales Order Lines, Purchase Order Lines, and Quote Lines."},{"id":"rpt8","text":"You click on a bar in a chart within the Report Builder. What happens?","options":[{"id":"a","text":"The data table below filters to show only the rows matching that bar segment","isCorrect":true},{"id":"b","text":"A new report opens for that specific segment"},{"id":"c","text":"The bar is highlighted but nothing else changes"},{"id":"d","text":"The chart zooms into that bar segment, showing sub-categories"}],"explanation":"Clicking a bar or pie/doughnut slice activates drill-down filtering. The data table updates to show only the rows that match the clicked segment. Click the same segment again or use the breadcrumb to return to the full unfiltered view."},{"id":"rpt9","text":"Which roles have access to the Reports module?","options":[{"id":"a","text":"All roles including Engineers and Production Workers"},{"id":"b","text":"Admin, Manager, Office Manager, and PM only","isCorrect":true},{"id":"c","text":"Admin and Manager only"},{"id":"d","text":"Admin only"}],"explanation":"The Reports module is restricted to Admin, Manager, Office Manager, and PM roles. Engineers and Production Workers do not have direct access to the full reports page, though they can view personal reports (My Work History, My Time Log) through their respective feature pages."},{"id":"rpt10","text":"You want to see a flow diagram showing how quotes convert into cash through the order lifecycle. Where do you go?","options":[{"id":"a","text":"Reports → Sankey Flow Reports → Quote-to-Cash","isCorrect":true},{"id":"b","text":"Reports → Pre-Built → Quote-to-Close"},{"id":"c","text":"Reports → Builder → select Quotes entity source"},{"id":"d","text":"Dashboard → Financial widget"}],"explanation":"The Quote-to-Cash Sankey diagram is one of 10 Sankey flow visualizations available under Reports → Sankey. It shows the flow from quotes through sales orders, shipments, invoices, to payments. The pre-built Quote-to-Close report shows conversion rates, not the visual flow."},{"id":"rpt11","text":"After running a custom report in the Report Builder, you want to download the results. What export option is available directly in the builder?","options":[{"id":"a","text":"CSV — click the CSV button that appears after running the report","isCorrect":true},{"id":"b","text":"Excel — click the Excel button in the toolbar"},{"id":"c","text":"PDF — click the PDF button next to the chart"},{"id":"d","text":"No export is available — you must copy-paste from the table"}],"explanation":"The Report Builder shows a CSV export button in the actions bar after a report has been run. It exports all result rows with the selected columns as a comma-separated file. PDF export is available via the server-side API endpoint, but the primary in-builder export is CSV."},{"id":"rpt12","text":"You have a saved report that you want to modify. How do you update it?","options":[{"id":"a","text":"Load the saved report from the dropdown, modify the configuration, then click Save — it updates the existing report","isCorrect":true},{"id":"b","text":"Delete the old report, make changes, and save as a new report"},{"id":"c","text":"Saved reports cannot be modified — you must create a new one"},{"id":"d","text":"Right-click the saved report name and select Edit"}],"explanation":"When you load a saved report from the toolbar dropdown, modify any settings (columns, filters, chart, etc.), and click Save, it updates the existing saved report with the new configuration. You can also delete a saved report using the red trash icon next to the dropdown."}]}"""
        });

        Log.Information("Seeded Reports training modules");
    }
}
